var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"고해성사를 할 일이 있어?","JPN":"告解したいことがあるって？","ENG":"Need to make a confession?","TWN":"你有什麼需要告解的事嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그렇다면 계약서에 따라서 청구할 비용은…….","JPN":"じゃあ、契約書に従って費用を請求……","ENG":"Well then, according to the contract, the fee to charge would be...","TWN":"如果是這樣，按照合約要收取的費用是……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"응? 그게 아니라 날 당신 곁에 두고 싶다고?","JPN":"うん？　そうじゃなくて、あなたのそばにいてほしいって？","ENG":"Huh? You don't mean that, but you're saying you want me by your side?","TWN":"嗯？你不是要告解，而是想讓我待在你身邊？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"전속 퇴마사는 값이 꽤 비싼데, 괜찮겠어?","JPN":"専属エクソシストは結構高いよ。大丈夫？","ENG":"A personal exorcist is quite pricey, you know. Are you sure about this?","TWN":"專屬的驅魔師可是很貴的，你真的沒問題嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"뭐, 당신이라면 분명 아무렇지 않게 계약서를 내밀겠지만…….","JPN":"ま、あなたならきっと何ともなく契約書を突きつけるでしょうけど……","ENG":"Well, I'm sure you'd hand over the contract without a second thought...","TWN":"看你這樣子，應該會毫不在意地把合約拿出來吧……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만 나 같은 사기…… 퇴마사 말고도 당신 곁엔 능력 있는 사람이 많잖아?","JPN":"でも、私みたいな詐欺……エクソシストじゃなくても、あなたのそばには能力のある人が多いでしょう？","ENG":"But you've got plenty of capable people around you instead of someone like me, a scam arti– I mean, exorcist?","TWN":"但你身邊應該有很多有能力的人吧？何必找我這個騙……不，是驅魔師？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그런 당신이 무슨 이유로 날 곁에 두고 싶을까?","JPN":"そんなあなたが、どうして私がそばにいてほしいと思ってるの？","ENG":"So why would someone like you want me by your side?","TWN":"你想把我留在身邊的理由是什麼？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"병을 고쳐주고 싶어서……?","JPN":"病気を治療してあげたい……？","ENG":"Because you want to cure my sickness...?","TWN":"是因為……想治好我的病？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"엄밀히 말하면 난 당신 돈을 뜯으러 온 거야.","JPN":"厳密に言うと、私はあなたからお金をせびり取るために来たんだよ。","ENG":"Strictly speaking, I'm here to get your money.","TWN":"嚴格來說，我是想從你身上弄點錢才來的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그런 나를…… 고작 그런 이유로 곁에 두고 싶다고?","JPN":"そんな私を……ただそんな理由で？","ENG":"You want to keep someone like me by your side... for that kind of reason?","TWN":"像我這樣的人……你竟然只是因為這種理由就想留在身邊？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"사람이 호구 같은 건지, 착한 건지…….","JPN":"バカなのか、お人よしなのか……","ENG":"Are you just naive or too good-hearted...?","TWN":"你這個人，是太傻還是太天真……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"당신이라면 알겠지만, 난 병에 걸려서 언제 어떻게 될지 몰라.","JPN":"あなたならわかってるでしょうけど、私は病気のせいでいつどうなるかわからない。","ENG":"You'd know, but due to my sickness, I don't know when what's gonna happen.","TWN":"你應該知道，我有病，不知道什麼時候會發生什麼事。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"당신에게 무슨 위협이 될지 모른다고.","JPN":"あなたの脅威になるかもしれないんだよ。","ENG":"I could become a threat to you, you know.","TWN":"也不知道會不會對你造成什麼危險。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그런데도 여전히 곁에 두고 싶다는 거야?","JPN":"それでも相変わらずそばにいてほしいって思ってる？","ENG":"And you still want to keep me around?","TWN":"即便如此，你還是想讓我待在你身邊嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……진심인가 보네.","JPN":"……本気みたいね。","ENG":"...You really mean it, huh?","TWN":"……看你好像是認真的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그래. 그동안 봐 온 당신이라면 뭔가 방법이 있겠지.","JPN":"そう。今まで見てきたあなたなら、何か方法があるんでしょう。","ENG":"Yeah. If anyone can find a way, it's you.","TWN":"好吧，畢竟我也一直在觀察你，我知道你一定有辦法的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"당신을 믿을게. 그간 날 믿고 꼬박꼬박 의뢰금을 준 것에 대한 보답이야.","JPN":"あなたを信じる。今まで私を信じて依頼料を支払ってきてくれたお礼だよ。","ENG":"I'll trust you. This is my way of repaying you for always trusting and paying me.","TWN":"我相信你。這是回報你一直以來信任我，而且定期支付委託費的心意。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만 전속 퇴마사가 비싸다는 건 사실이거든?","JPN":"でも、専属エクソシストが高いっていうのは本当だから。","ENG":"But it's true that a personal exorcist doesn't come cheap.","TWN":"不過，專屬驅魔師是真的很貴喔？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼, 연봉 얘기부터 먼저 해볼까?","JPN":"じゃあ、年収の話からしようか？","ENG":"How about we start by discussing my salary?","TWN":"那我們就先從年薪談起吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_COIN"}]`);export{e as default};